377→function isVersionCompatible(version: string): boolean {
378→  // For now, require exact match on major.minor
379→  const [reqMajor, reqMinor] = version.split(".").map(Number);
380→  const [ourMajor, ourMinor] = PROTOCOL_VERSION.split(".").map(Number);
381→  return reqMajor === ourMajor && reqMinor === ourMinor;
382→}
