  1→/**
  2→ * Setup and generator module loader for the Shatter TypeScript frontend.
  3→ *
  4→ * Loads user-provided setup/teardown and generator files using the same
  5→ * vm.createContext + TypeScript transpile pattern as executor.ts.
  6→ */
  7→
  8→import * as ts from "typescript";
  9→import * as fs from "node:fs";
 10→import * as vm from "node:vm";
 11→import * as path from "node:path";
 12→import { createRequire } from "node:module";
 13→import type { SetupLevel, SetupContextStack, GeneratorKind } from "./protocol.js";
 14→
 15→/** Default setup timeout in milliseconds (30 seconds). */
 16→const DEFAULT_SETUP_TIMEOUT_MS = 30_000;
 17→
 18→/**
 19→ * Read SHATTER_SETUP_TIMEOUT env var (seconds) and return milliseconds.
 20→ * Default: 30s. Ignores non-positive or non-numeric values.
 21→ */
 22→export function getSetupTimeoutMs(): number {
 23→  const raw = process.env["SHATTER_SETUP_TIMEOUT"];
 24→  if (raw !== undefined) {
 25→    const secs = parseFloat(raw);
 26→    if (Number.isFinite(secs) && secs > 0) {
 27→      return secs * 1000;
 28→    }
 29→  }
 30→  return DEFAULT_SETUP_TIMEOUT_MS;
 31→}
 32→
 33→/** A loaded setup module with its exports available for calling. */
 34→export interface SetupModule {
 35→  exports: Record<string, unknown>;
 36→  filePath: string;
 37→}
 38→
 39→/** A loaded generator module with its exports available for calling. */
 40→export interface GeneratorModule {
 41→  exports: Record<string, unknown>;
 42→  filePath: string;
 43→}
 44→
 45→/**
 46→ * Transpile and load a TypeScript/JavaScript file, returning its exports.
 47→ */
 48→function loadAndTranspile(filePath: string): Record<string, unknown> {
 49→  const absolutePath = path.resolve(filePath);
 50→  const source = fs.readFileSync(absolutePath, "utf-8");
 51→  const result = ts.transpileModule(source, {
 52→    compilerOptions: {
 53→      target: ts.ScriptTarget.ES2022,
 54→      module: ts.ModuleKind.CommonJS,
 55→      esModuleInterop: true,
 56→      strict: true,
 57→      jsx: ts.JsxEmit.ReactJSX,
 58→    },
 59→    fileName: absolutePath,
 60→  });
 61→
 62→  const targetRequire = createRequire(absolutePath);
 63→  const moduleExports: Record<string, unknown> = {};
 64→  const moduleObj = { exports: moduleExports };
 65→
 66→  const sandbox = vm.createContext({
 67→    module: moduleObj,
 68→    exports: moduleExports,
 69→    require: targetRequire,
 70→    console,
 71→    process,
 72→    Buffer,
 73→    setTimeout,
 74→    clearTimeout,
 75→    setInterval,
 76→    clearInterval,
 77→    __filename: absolutePath,
 78→    __dirname: path.dirname(absolutePath),
 79→  });
 80→
 81→  vm.runInContext(result.outputText, sandbox, { filename: absolutePath });
 82→
 83→  const finalExports = (sandbox as Record<string, unknown>)["module"] as {
 84→    exports: Record<string, unknown>;
 85→  };
 86→  return finalExports.exports;
 87→}
 88→
 89→/**
 90→ * Load a setup module file. The file should export a `setup()` function
 91→ * and optionally a `teardown()` function.
 92→ */
 93→export function loadSetupModule(file: string): SetupModule {
 94→  const exports = loadAndTranspile(file);
 95→  return { exports, filePath: path.resolve(file) };
 96→}
 97→
 98→/**
 99→ * Run the setup() export from a loaded setup module.
100→ *
101→ * Calls `module.setup(scope, parentContext?)` and returns the setup_context.
102→ * Supports both sync and async setup functions. Applies SHATTER_SETUP_TIMEOUT.
103→ */
104→export async function runSetup(
105→  setupModule: SetupModule,
106→  scope: string,
107→  _level: SetupLevel,
108→  parentContext?: SetupContextStack | null,
109→): Promise<unknown> {
110→  const setupFn = setupModule.exports["setup"];
111→  if (typeof setupFn !== "function") {
112→    throw new Error(
113→      `Setup file "${setupModule.filePath}" does not export a setup() function. ` +
114→      `Available exports: ${Object.keys(setupModule.exports).join(", ")}`,
115→    );
116→  }
117→
118→  const result = (setupFn as (scope: string, parentContext?: SetupContextStack | null) => unknown)(
119→    scope,
120→    parentContext ?? null,
121→  );
122→
123→  // Handle async setup functions
124→  if (result != null && typeof (result as PromiseLike<unknown>).then === "function") {
125→    const timeoutMs = getSetupTimeoutMs();
126→    return Promise.race([
127→      result as Promise<unknown>,
128→      new Promise<never>((_, reject) =>
129→        setTimeout(() => reject(new Error(`Setup timed out after ${timeoutMs}ms`)), timeoutMs),
130→      ),
131→    ]);
132→  }
133→
134→  return result;
135→}
