133→/// Run a complete setup: compile the file and execute the resulting binary.
134→/// Returns the opaque context value for downstream Execute commands.
135→pub fn run_setup(
136→    file_path: &Path,
137→    level: SetupLevel,
138→    scope: &str,
139→    parent_context: Option<&SetupContextStack>,
140→) -> Result<SetupResult, SetupError> {
141→    let binary_path = compile_setup_file(file_path)?;
142→    let result = run_setup_binary(&binary_path, level, scope, parent_context);
143→
144→    // Best-effort cleanup of the compiled binary
145→    let _ = std::fs::remove_file(&binary_path);
146→
147→    result
