 22→
 23→const defaultExecTimeout = 5 * time.Second
 24→const defaultBuildTimeout = 30 * time.Second
 25→
 26→// maxTimeoutSecs guards against overflow when converting float64 seconds to
 27→// time.Duration. time.Duration is int64 nanoseconds (max ≈292 years); we cap
 28→// at 24 hours which is well beyond any realistic execution timeout.
 29→const maxTimeoutSecs = 86400
 30→
 31→// execTimeout returns the execution timeout, reading from SHATTER_EXEC_TIMEOUT
 32→// env var (in seconds) with a fallback to defaultExecTimeout.
 33→func execTimeout() time.Duration {
 34→	if d, ok := parseTimeoutEnv("SHATTER_EXEC_TIMEOUT"); ok {
 35→		return d
 36→	}
 37→	return defaultExecTimeout
 38→}
 39→
 40→// buildTimeout returns the build timeout, reading from SHATTER_BUILD_TIMEOUT
 41→// env var (in seconds) with a fallback to defaultBuildTimeout.
 42→func buildTimeout() time.Duration {
 43→	if d, ok := parseTimeoutEnv("SHATTER_BUILD_TIMEOUT"); ok {
 44→		return d
 45→	}
 46→	return defaultBuildTimeout
 47→}
 48→
 49→// parseTimeoutEnv reads an env var as seconds and returns a valid duration.
 50→// Returns false for missing, non-numeric, non-positive, overflow, or sub-
 51→// nanosecond values — callers fall back to their default.
 52→func parseTimeoutEnv(key string) (time.Duration, bool) {
 53→	s := os.Getenv(key)
 54→	if s == "" {
 55→		return 0, false
 56→	}
 57→	secs, err := strconv.ParseFloat(s, 64)
 58→	if err != nil || secs <= 0 || math.IsInf(secs, 0) || math.IsNaN(secs) || secs >= maxTimeoutSecs {
 59→		return 0, false
 60→	}
 61→	d := time.Duration(secs * float64(time.Second))
 62→	if d <= 0 {
 63→		return 0, false
 64→	}
 65→	return d, true
 66→}
