  1→// Package setup provides setup file loading and context management for the
  2→// Go frontend. Setup files are compiled and run as subprocesses; their JSON
  3→// stdout output becomes the opaque setup_context returned to the core engine.
  4→package setup
  5→
  6→import (
  7→	"encoding/json"
  8→	"fmt"
  9→	"os"
 10→	"os/exec"
 11→	"path/filepath"
 12→	"sync"
 13→)
 14→
 15→// contextKey uniquely identifies a setup context by scope and level.
 16→type contextKey struct {
 17→	Scope string
 18→	Level string
 19→}
 20→
 21→// Loader compiles and runs Go setup files, caching their contexts by
 22→// (scope, level) for later teardown.
 23→type Loader struct {
 24→	mu       sync.Mutex
 25→	contexts map[contextKey]json.RawMessage
 26→}
 27→
 28→// NewLoader creates a Loader with an empty context cache.
 29→func NewLoader() *Loader {
 30→	return &Loader{
 31→		contexts: make(map[contextKey]json.RawMessage),
 32→	}
 33→}
 34→
 35→// RunSetup compiles and executes the setup file, returning the opaque context.
 36→// The setup file must be a valid Go source file with a main function that
 37→// prints a single JSON object to stdout. Environment variables are set to
 38→// communicate scope, level, and parent context to the setup process.
 39→func (l *Loader) RunSetup(file, scope, level string, projectRoot *string, parentContext json.RawMessage) (json.RawMessage, error) {
 40→	absFile, err := filepath.Abs(file)
 41→	if err != nil {
 42→		return nil, fmt.Errorf("resolving setup file path: %w", err)
 43→	}
 44→	if _, err := os.Stat(absFile); err != nil {
 45→		return nil, fmt.Errorf("setup file not found: %s", absFile)
 46→	}
 47→
 48→	// Build the setup file to a temporary binary.
 49→	tmpDir, err := os.MkdirTemp("", "shatter-setup-*")
 50→	if err != nil {
 51→		return nil, fmt.Errorf("creating temp dir: %w", err)
 52→	}
 53→	defer os.RemoveAll(tmpDir)
 54→
 55→	binPath := filepath.Join(tmpDir, "setup")
 56→	buildCmd := exec.Command("go", "build", "-o", binPath, absFile)
 57→	buildCmd.Dir = filepath.Dir(absFile)
 58→	if out, err := buildCmd.CombinedOutput(); err != nil {
 59→		return nil, fmt.Errorf("building setup file: %s: %w", string(out), err)
 60→	}
 61→
 62→	// Run the compiled setup binary.
 63→	runCmd := exec.Command(binPath)
 64→	runCmd.Dir = filepath.Dir(absFile)
 65→	runCmd.Env = append(os.Environ(),
 66→		"SHATTER_SETUP_SCOPE="+scope,
