 78→		if exitErr, ok := err.(*exec.ExitError); ok {
 79→			return nil, fmt.Errorf("setup file exited with error: %s: %s", exitErr, string(exitErr.Stderr))
 80→		}
 81→		return nil, fmt.Errorf("running setup file: %w", err)
 82→	}
 83→
 84→	// Validate that the output is valid JSON.
 85→	stdout = trimTrailingNewlines(stdout)
 86→	if len(stdout) == 0 {
 87→		// No output — use empty object as context.
 88→		stdout = []byte("{}")
 89→	}
 90→	if !json.Valid(stdout) {
 91→		return nil, fmt.Errorf("setup file output is not valid JSON: %s", string(stdout))
 92→	}
 93→
 94→	ctx := json.RawMessage(stdout)
 95→
 96→	// Cache the context.
 97→	l.mu.Lock()
 98→	l.contexts[contextKey{Scope: scope, Level: level}] = ctx
 99→	l.mu.Unlock()
