	if !strings.Contains(jsonStr, `"constraint"`) {
		t.Errorf("JSON must contain constraint field, got: %s", jsonStr)
	}
	if !strings.Contains(jsonStr, `"kind":"unknown"`) {
		t.Errorf("JSON constraint must have kind=unknown, got: %s", jsonStr)
	}
}

